// Build the LM Studio prompt from incoming file contents + question
const body = $input.first().json.body || $input.first().json;

const files = body.files || [];
const question = body.question || 'Analyse the codebase structure and key patterns';
const maxTokens = body.maxTokens || 4096;

// Build file content section
const fileSection = files.map(f => `### ${f.path}\n\`\`\`\n${f.content}\n\`\`\``).join('\n\n');

const systemPrompt = 'You are a codebase analyst. Given project files and a question, produce a concise structured analysis. Be factual and precise.';

const userPrompt = `## Question\n${question}\n\n## Project Files (${files.length} files)\n${fileSection}\n\n## Instructions\nProduce a structured analysis with these sections:\n1. **Project Structure**: Architecture, framework, key directories\n2. **Relevant Files**: Files most relevant to the question, with brief descriptions\n3. **Key Patterns**: Conventions, abstractions, naming patterns used\n4. **Dependencies**: Relevant packages and their purpose\n5. **Suggested Approach**: How to approach the task given the codebase\n\nKeep total output under 3000 words. Be concise.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    maxTokens,
    model: body.model || ''
  }
}];

// Extract the analysis from LM Studio response
const response = $input.first().json;
const analysis = response.choices?.[0]?.message?.content || '';
const model = response.model || 'local';
const usage = response.usage || {};

return [{
  json: {
    ok: true,
    analysis,
    model,
    usage: {
      promptTokens: usage.prompt_tokens || 0,
      completionTokens: usage.completion_tokens || 0,
      totalTokens: usage.total_tokens || 0
    }
  }
}];

// Meshwork webhook caller verification.
// Accepts EITHER:
//   1) the runner's HMAC signature (x-meshwork-signature over `${ts}.${body}`)
//   2) a shared token in ?token= or the x-webhook-token header (for external
//      callers like Jira webhook URLs)
// Enforcement is off until WEBHOOK_VERIFICATION_ENFORCE=true in .env (values
// are substituted at import time by scripts/import-workflows.sh).
const crypto = require('crypto');

const ENFORCE = '{{WEBHOOK_VERIFICATION_ENFORCE}}'.toLowerCase() === 'true';
const RUNNER_SECRET = '{{RUNNER_SECRET}}';
const SHARED_TOKEN = '{{WEBHOOK_SHARED_TOKEN}}';

const item = $input.first().json;
const headers = item.headers || {};
const query = item.query || {};
const body = item.body ?? {};

const isPlaceholder = (v) => !v || v.indexOf('{{') === 0;
let ok = false;

// 1) Runner HMAC
const sig = headers['x-meshwork-signature'];
const ts = headers['x-meshwork-timestamp'];
if (sig && ts && !isPlaceholder(RUNNER_SECRET)) {
  const age = Math.abs(Date.now() - Number(ts));
  if (age < 5 * 60 * 1000) {
    const expected = 'sha256=' + crypto.createHmac('sha256', RUNNER_SECRET)
      .update(ts + '.' + JSON.stringify(body)).digest('hex');
    const a = crypto.createHash('sha256').update(expected).digest();
    const b = crypto.createHash('sha256').update(String(sig)).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

// 2) Shared token
if (!ok && !isPlaceholder(SHARED_TOKEN)) {
  const provided = String(query.token || headers['x-webhook-token'] || '');
  if (provided) {
    const a = crypto.createHash('sha256').update(provided).digest();
    const b = crypto.createHash('sha256').update(SHARED_TOKEN).digest();
    if (crypto.timingSafeEqual(a, b)) ok = true;
  }
}

if (!ok && ENFORCE) {
  throw new Error('Webhook verification failed: missing or invalid signature/token. See SECURITY.md (webhook verification).');
}

return $input.all();
